-- Add subclasses JSONB column to classes table
ALTER TABLE public.classes ADD COLUMN IF NOT EXISTS subclasses jsonb DEFAULT '[]'::jsonb;

-- Update Barbarian with subclasses
UPDATE public.classes SET subclasses = '[
  {"name": "Путь Берсерка", "name_en": "Path of the Berserker", "level": 3, "description": "Берсерк — это воплощение неукротимой ярости. Когда вы впадаете в неистовство, вы становитесь машиной уничтожения, неспособной различать друзей и врагов.", "features": [
    {"name": "Неистовство", "level": 3, "description": "Начиная с 3 уровня, вы можете впасть в неистовство во время ярости. Если вы это делаете, вы можете совершать одну дополнительную атаку рукопашным оружием бонусным действием в каждом своём ходу, пока действует ярость. Когда ярость заканчивается, вы получаете один уровень истощения."},
    {"name": "Бездумная ярость", "level": 6, "description": "Начиная с 6 уровня, вы не можете быть очарованы или испуганы, пока находитесь в ярости. Если вы были очарованы или испуганы, когда впали в ярость, эффект приостанавливается на время действия ярости."},
    {"name": "Устрашающее присутствие", "level": 10, "description": "Начиная с 10 уровня, вы можете действием напугать кого-либо своим устрашающим присутствием. Выберите одно существо в пределах 30 футов. Если существо видит или слышит вас, оно должно пройти спасбросок Мудрости (Сл 8 + ваш бонус мастерства + модификатор Харизмы) или станет испуганным до конца вашего следующего хода."},
    {"name": "Возмездие", "level": 14, "description": "Начиная с 14 уровня, когда вы получаете урон от существа в пределах 5 футов, вы можете реакцией совершить атаку рукопашным оружием по этому существу."}
  ]},
  {"name": "Путь Воина Тотема", "name_en": "Path of the Totem Warrior", "level": 3, "description": "Путь воина тотема — это духовное путешествие, во время которого варвар принимает дух животного в качестве проводника, защитника и источника вдохновения.", "features": [
    {"name": "Искатель духов", "level": 3, "description": "Вы получаете возможность сотворять заклинания «Животная дружба» и «Говорить с животными» как ритуалы."},
    {"name": "Дух тотема", "level": 3, "description": "Выберите тотемного духа: Медведь (сопротивление всему урону кроме психического в ярости), Орёл (враги получают помеху при провоцированных атаках, Рывок бонусным действием), Волк (союзники получают преимущество при атаках против врагов в 5 футах от вас)."},
    {"name": "Аспект зверя", "level": 6, "description": "Выберите аспект: Медведь (удвоенная грузоподъёмность, преимущество проверок Силы при толкании/подъёме), Орёл (зрение на 1 милю, нет помехи к восприятию при тусклом свете), Волк (выслеживание в быстром темпе, скрытное перемещение)."},
    {"name": "Духовный странник", "level": 10, "description": "Вы можете сотворить «Общение с природой» как ритуал. Духи дают вам видение 1 мили вокруг."},
    {"name": "Тотемное единение", "level": 14, "description": "Выберите способность: Медведь (враги в 5 футах получают помеху при атаках по вашим союзникам), Орёл (скорость полёта в ярости), Волк (сбивание врага бонусным действием)."}
  ]},
  {"name": "Путь Предка", "name_en": "Path of the Ancestral Guardian", "level": 3, "description": "Варвары Пути Предка полагаются на духов своих предков, которые защищают их и сражаются рядом с ними.", "features": [
    {"name": "Защитники предков", "level": 3, "description": "Во время ярости первое существо, которое вы атакуете, становится отмеченным духами предков. До начала вашего следующего хода, если это существо атакует кого-то кроме вас, цель получает сопротивление урону, а существо атакует с помехой."},
    {"name": "Духовный щит", "level": 6, "description": "Когда существо в 30 футах от вас получает урон, вы можете реакцией уменьшить урон на 2к6 (3к6 на 10, 4к6 на 14 уровне)."},
    {"name": "Консультация с духами", "level": 10, "description": "Вы можете сотворить «Гадание» или «Ясновидение» без материальных компонентов. Мудрость — заклинательная характеристика. Раз между отдыхами."},
    {"name": "Мстительные предки", "level": 14, "description": "Когда вы используете Духовный щит для уменьшения урона, атакующий получает силовой урон, равный уменьшенному урону."}
  ]},
  {"name": "Путь Неистового Зверя", "name_en": "Path of the Beast", "level": 3, "description": "Варвары, следующие этому пути, черпают свою ярость из звериной искры, горящей в их душе.", "features": [
    {"name": "Форма зверя", "level": 3, "description": "При входе в ярость выберите: Укус (1к8, восстановление HP), Когти (1к6, дополнительная атака когтями), Хвост (1к8 колющий, +1к8 КД реакцией)."},
    {"name": "Дикая душа", "level": 6, "description": "Животные не будут атаковать вас первыми. Вы можете лазать и плавать со скоростью ходьбы."},
    {"name": "Заразительное безумие", "level": 10, "description": "Когда вы впадаете в ярость, союзники в 10 футах могут реакцией тоже впасть в безумие (бонус к урону и сопротивление на 1 минуту)."},
    {"name": "Зов охоты", "level": 14, "description": "Когда существо в 30 футах проваливает спасбросок от вашей атаки, вы можете бонусным действием переместиться к нему и совершить атаку."}
  ]}
]'::jsonb WHERE name_en = 'Barbarian';

