UPDATE public.classes SET subclasses = '[
  {"name": "Коллегия Знаний", "name_en": "College of Lore", "level": 3, "description": "Барды Коллегии Знаний знают понемногу обо всём, собирая обрывки знаний из самых разнообразных источников.", "features": [
    {"name": "Дополнительные владения", "level": 3, "description": "Вы получаете владение тремя навыками на ваш выбор."},
    {"name": "Разящее слово", "level": 3, "description": "Вы можете использовать Вдохновение барда, чтобы отвлечь, смутить или напугать существо. Реакцией вычтите кость из броска атаки, проверки характеристики или урона существа."},
    {"name": "Дополнительные тайны магии", "level": 6, "description": "Выберите два заклинания из любых классов. Они становятся заклинаниями барда."},
    {"name": "Несравненное мастерство", "level": 14, "description": "При проверке характеристики с владением навыком вы можете потратить Вдохновение барда, чтобы добавить кость к результату после броска, но до объявления успеха."}
  ]},
  {"name": "Коллегия Доблести", "name_en": "College of Valor", "level": 3, "description": "Барды Коллегии Доблести — это отважные скальды, чьи песни поддерживают дух воинов.", "features": [
    {"name": "Дополнительные владения", "level": 3, "description": "Вы получаете владение средними доспехами, щитами и воинским оружием."},
    {"name": "Боевое вдохновение", "level": 3, "description": "Существо может добавить кость Вдохновения к броску урона оружия или к КД против одной атаки."},
    {"name": "Дополнительная атака", "level": 6, "description": "Вы можете атаковать дважды при совершении действия Атака."},
    {"name": "Боевая магия", "level": 14, "description": "Когда вы действием сотворяете заклинание барда, вы можете бонусным действием совершить одну атаку оружием."}
  ]},
  {"name": "Коллегия Мечей", "name_en": "College of Swords", "level": 3, "description": "Барды Коллегии Мечей развлекают демонстрацией боевого мастерства с клинками.", "features": [
    {"name": "Боевой стиль", "level": 3, "description": "Выберите Дуэлянт (+2 к урону одноручным оружием) или Сражение двумя оружиями (добавить модификатор к урону второй атаки)."},
    {"name": "Росчерк клинка", "level": 3, "description": "При попадании атакой оружием потратьте Вдохновение: Защитный росчерк (+КД), Рубящий росчерк (урон второму), Мобильный росчерк (отход)."},
    {"name": "Дополнительная атака", "level": 6, "description": "Вы можете атаковать дважды при совершении действия Атака."},
    {"name": "Мастер клинка", "level": 14, "description": "При использовании Росчерка клинка бросьте к6 вместо траты кости Вдохновения, если у вас нет использований."}
  ]},
  {"name": "Коллегия Красноречия", "name_en": "College of Eloquence", "level": 3, "description": "Барды этой коллегии — мастера слова, способные убедить кого угодно в чём угодно.", "features": [
    {"name": "Серебряный язык", "level": 3, "description": "При проверке Убеждения или Обмана результат меньше 10 на кости считается как 10."},
    {"name": "Обезоруживающие слова", "level": 3, "description": "Бонусным действием потратьте Вдохновение барда: существо в 60 футах должно пройти спасбросок Мудрости или получить помеху на следующий спасбросок до конца вашего следующего хода."},
    {"name": "Непоколебимое красноречие", "level": 6, "description": "Если существо использует Вдохновение и бросок проваливается, оно сохраняет Вдохновение."},
    {"name": "Заразительное вдохновение", "level": 14, "description": "Когда существо успешно использует Вдохновение, другое существо в 60 футах получает Вдохновение без траты вашего использования."}
  ]}
]'::jsonb WHERE name_en = 'Bard';

-- Update Cleric with subclasses (Domains)
UPDATE public.classes SET subclasses = '[
  {"name": "Домен Жизни", "name_en": "Life Domain", "level": 1, "description": "Боги жизни покровительствуют жизненной силе и здоровью, исцеляя больных и раненых.", "features": [
