    {"name": "Видения прошлого", "level": 17, "description": "Медитацией узнайте историю предмета или области за последние дни."}
  ]},
  {"name": "Домен Обмана", "name_en": "Trickery Domain", "level": 1, "description": "Боги обмана — это провокаторы и смутьяны, покровители воров и мошенников.", "features": [
    {"name": "Благословение обманщика", "level": 1, "description": "Действием дайте существу преимущество на проверки Скрытности на 1 час."},
    {"name": "Призыв дубликата", "level": 2, "description": "Божественное вмешательство: создайте иллюзию себя в 30 футах на 1 минуту. Бонусным действием перемещайте на 30 футов."},
    {"name": "Канал божественной энергии: Плащ теней", "level": 6, "description": "Действием станьте невидимым до конца следующего хода или до атаки/заклинания."},
    {"name": "Божественный удар", "level": 8, "description": "Раз в ход добавьте 1к8 урона ядом к атаке оружием (2к8 на 14 уровне)."},
    {"name": "Улучшенный дубликат", "level": 17, "description": "Вы можете сотворять заклинания из местоположения дубликата."}
  ]},
  {"name": "Домен Порядка", "name_en": "Order Domain", "level": 1, "description": "Боги порядка олицетворяют дисциплину и преданность законам.", "features": [
    {"name": "Дополнительные владения", "level": 1, "description": "Вы получаете владение тяжёлыми доспехами и навыком Запугивание или Убеждение."},
    {"name": "Голос власти", "level": 1, "description": "При заклинании 1+ круга на союзника, он может реакцией атаковать."},
    {"name": "Божественное требование", "level": 2, "description": "Божественное вмешательство: существа в 30 футах должны пройти Мудрость или упасть ничком и бросить что держат."},
    {"name": "Воплощение закона", "level": 6, "description": "При заклинании Очарования можете нацелить второе существо (модификатор Мудрости раз между отдыхами)."},
    {"name": "Божественный удар", "level": 8, "description": "Раз в ход добавьте 1к8 психического урона к атаке оружием (2к8 на 14 уровне)."},
    {"name": "Гнев порядка", "level": 17, "description": "При попадании по очарованному существу оно получает дополнительно 2к8 психического урона."}
  ]}
]'::jsonb WHERE name_en = 'Cleric';

