    {"name": "Восстановление природной силы", "level": 2, "description": "При коротком отдыхе восстановите ячейки заклинаний с суммарным уровнем до половины уровня друида."},
    {"name": "Заклинания круга", "level": 3, "description": "Получите дополнительные заклинания в зависимости от выбранной местности (Арктика, Побережье, Пустыня, Лес, Луга, Горы, Болото, Подземелье)."},
    {"name": "Шаг по земле", "level": 6, "description": "Немагический труднопроходимый ландшафт не влияет на вас. Проходите сквозь немагические растения без замедления и урона."},
    {"name": "Покровительство природы", "level": 10, "description": "Вы не можете быть очарованы или испуганы элементалами и феями, иммунитет к болезням и ядам."},
    {"name": "Природное убежище", "level": 14, "description": "Звери и растения неохотно атакуют вас и должны пройти Мудрость, чтобы атаковать."}
  ]},
  {"name": "Круг Луны", "name_en": "Circle of the Moon", "level": 2, "description": "Друиды Круга Луны — яростные защитники дикой природы, мастера превращений.", "features": [
    {"name": "Боевая дикая форма", "level": 2, "description": "Превращение бонусным действием. Можно превращаться в зверей с показателем опасности 1 (опасность = уровень / 3 на 6+)."},
    {"name": "Улучшенная дикая форма", "level": 6, "description": "Атаки в дикой форме считаются магическими."},
