    {"name": "Зомби-грибы", "level": 6, "description": "Реакцией оживите маленького или среднего зверя или гуманоида как зомби на 1 час."},
    {"name": "Распространение спор", "level": 10, "description": "Гало спор действует в 30 футах."},
    {"name": "Грибное тело", "level": 14, "description": "Вы не можете быть ослеплены, оглушены, испуганы, отравлены или сбиты с ног."}
