  {"name": "Охотник", "name_en": "Hunter", "level": 3, "description": "Охотник принимает свою роль как оплот между цивилизацией и ужасами дикой местности.", "features": [
    {"name": "Добыча охотника", "level": 3, "description": "Выберите: Убийца колоссов (+1к8 урона по существам ниже максимального HP), Убийца великанов (реакция — атака при атаке Большого+ существа), Убийца орд (+1 враг при атаке если рядом)."},
    {"name": "Защитная тактика", "level": 7, "description": "Выберите: Уклончивость от многоатаковых (преимущество на спасброски от многоатаковых способностей), Защита от многоатаковых (−4 урона при множественных атаках), Стальная воля (преимущество от испуга)."},
    {"name": "Мультиатака", "level": 11, "description": "Выберите: Залп (атака любого количества существ в 10 футах друг от друга) или Вихрь (атака всех существ в 5 футах)."},
    {"name": "Превосходная защита охотника", "level": 15, "description": "Выберите: Уклонение (Ловкость на половину урона = 0 урона), Стоять на страже (реакцией атаковать существо в 5 футах, атакующее союзника), Непоколебимость (преимущество на спасброски когда HP ≤ половины)."}
  ]},
  {"name": "Повелитель зверей", "name_en": "Beast Master", "level": 3, "description": "Повелитель зверей развивает связь со зверем, который становится его верным спутником.", "features": [
    {"name": "Спутник следопыта", "level": 3, "description": "Получите зверя-спутника с опасностью 1/4 или ниже. В бою он действует по вашей инициативе и выполняет ваши команды."},
    {"name": "Исключительная дрессировка", "level": 7, "description": "В ход, когда зверь не атакует, можете бонусным действием приказать ему Рывок, Отход, Помощь или Уклонение."},
    {"name": "Звериная ярость", "level": 11, "description": "Когда вы приказываете зверю атаковать, он может совершить две атаки."},
    {"name": "Разделённые заклинания", "level": 15, "description": "Заклинания с дальностью «На себя» также действуют на вашего зверя-спутника."}
  ]},
  {"name": "Сумрачный охотник", "name_en": "Gloom Stalker", "level": 3, "description": "Сумрачные охотники наиболее комфортно чувствуют себя во тьме.", "features": [
    {"name": "Магия сумрака", "level": 3, "description": "Дополнительные заклинания: Маскировка (3), Верёвочный трюк (5), Страх (9), Высшая невидимость (13), Искажение (17)."},
    {"name": "Ужасное нападение", "level": 3, "description": "В первый ход боя +10 к скорости. Если атакуете — одна дополнительная атака с +1к8 урона."},
    {"name": "Зрение в темноте", "level": 3, "description": "Тёмное зрение 60 футов. Если уже есть — +30 футов. Невидимы для существ, полагающихся на тёмное зрение."},
    {"name": "Железный разум", "level": 7, "description": "Владение спасбросками Мудрости. Если уже есть — выберите Интеллект или Харизму."},
    {"name": "Шаг сквозь тень", "level": 11, "description": "Если вы в тусклом свете/тьме и промахиваетесь, можете бонусным действием атаковать другую цель."},
    {"name": "Туманный охотник", "level": 15, "description": "Если существо атакует вас в тусклом свете/тьме и промахивается, вы можете реакцией атаковать его."}
  ]},
  {"name": "Роевой хранитель", "name_en": "Swarmkeeper", "level": 3, "description": "Рой духов природы сопровождает и защищает этого следопыта.", "features": [
    {"name": "Собранный рой", "level": 3, "description": "Выберите тип роя (насекомые, феи, духи). Раз в ход при попадании: +1к6 урона, или толкнуть на 15 футов, или передвинуться на 5 футов."},
    {"name": "Магия роя", "level": 3, "description": "Дополнительные заклинания: Волшебный огонёк, Рой (3), Паутина (5), Газообразная форма (9), Мор (13), Нашествие насекомых (17)."},
    {"name": "Ползучий рой", "level": 7, "description": "Бонусным действием переместитесь роем на 5 футов. Получите половинное укрытие и сопротивление от одной атаки."},
    {"name": "Роевой взрыв", "level": 11, "description": "При использовании Собранного роя: урон 1к8, толчок 15 футов, движение 10 футов."},
    {"name": "Могучий рой", "level": 15, "description": "Вы можете летать со скоростью ходьбы. Рой поддерживает вас, но только до конца следующего хода если вы не на земле."}
  ]}
]'::jsonb WHERE name_en = 'Ranger';

-- Update Rogue with subclasses (Archetypes)
UPDATE public.classes SET subclasses = '[
  {"name": "Вор", "name_en": "Thief", "level": 3, "description": "Вор оттачивает навыки воровства, взлома и проникновения.", "features": [
    {"name": "Ловкие руки", "level": 3, "description": "Бонусное действие для Ловкости рук, обезвреживания ловушек, вскрытия замков или использования предмета."},
    {"name": "Повышенное лазание", "level": 3, "description": "Лазание не стоит дополнительного перемещения. Длина прыжка +модификатор Ловкости футов."},
    {"name": "Неподвижность", "level": 9, "description": "Преимущество на Скрытность если двигаетесь не более половины скорости."},
    {"name": "Использование магических предметов", "level": 13, "description": "Вы можете игнорировать требования классов, рас и уровней для магических предметов."},
    {"name": "Рефлексы вора", "level": 17, "description": "Два хода в первом раунде боя. Первый ход — по инициативе, второй — по инициативе минус 10."}
  ]},
  {"name": "Убийца", "name_en": "Assassin", "level": 3, "description": "Убийца — смертельный агент, мастер маскировки и яда.", "features": [
    {"name": "Дополнительные владения", "level": 3, "description": "Вы получаете владение набором отравителя и набором для грима."},
    {"name": "Убийственный удар", "level": 3, "description": "Преимущество против существ, не действовавших в бою. Попадание по застигнутому врасплох — критическое."},
    {"name": "Мастерство проникновения", "level": 9, "description": "Неоспоримая маскировка и ложная личность за неделю и 25 зм."},
    {"name": "Самозванец", "level": 13, "description": "Создайте ложную личность за 3 часа и 25 зм. Имитируйте речь и поведение."},
    {"name": "Смертельный удар", "level": 17, "description": "При попадании по застигнутому врасплох: Телосложение или урон удваивается."}
  ]},
  {"name": "Мистический ловкач", "name_en": "Arcane Trickster", "level": 3, "description": "Мистический ловкач сочетает искусство вора с магией школ Иллюзий и Очарования.", "features": [
    {"name": "Использование заклинаний", "level": 3, "description": "Базовая характеристика — Интеллект. Заклинания из школ Иллюзий и Очарования (некоторые из любых школ на 3, 8, 14, 20 уровнях)."},
    {"name": "Рука мага", "level": 3, "description": "Заговор «Волшебная рука» невидим и может: красть, подкладывать, открывать замки, обезвреживать ловушки на расстоянии."},
    {"name": "Магическая засада", "level": 9, "description": "Если вы скрыты от существа при сотворении заклинания, оно получает помеху на спасбросок."},
    {"name": "Универсальный ловкач", "level": 13, "description": "При использовании Волшебной руки можете бонусным действием использовать Ловкие руки."},
    {"name": "Похититель заклинаний", "level": 17, "description": "Реакцией при заклинании 1-4 круга по вам можете потратить ячейку, чтобы отменить заклинание и сотворить его самому."}
  ]},
  {"name": "Фантом", "name_en": "Phantom", "level": 3, "description": "Фантомы имеют связь со смертью и миром духов.", "features": [
    {"name": "Шёпот мёртвых", "level": 3, "description": "Получите владение одним навыком или инструментом до следующего отдыха."},
    {"name": "Горе из-за могилы", "level": 3, "description": "При Скрытой атаке нанесите половину урона второй цели в 30 футах. 1 раз за ход."},
    {"name": "Жетоны умерших", "level": 9, "description": "При смерти существа в 30 футах получите Жетон души. Потратьте, чтобы задать вопрос духу или добавить к6 к атаке/спасброску."},
    {"name": "Дух в ночи", "level": 13, "description": "Бонусным действием примите призрачную форму на 10 минут. Полёт 10 футов, проход сквозь существ и предметы (урон 1к10 при застревании)."},
    {"name": "Смертельный друг", "level": 17, "description": "Горе из-за могилы: полный урон второй цели вместо половины. При сборе Жетона души — 2к6."}
  ]},
  {"name": "Ловец душ", "name_en": "Soulknife", "level": 3, "description": "Ловцы душ проявляют псионические клинки из чистой психической энергии.", "features": [
    {"name": "Псионическая сила", "level": 3, "description": "Получите кости Псионической энергии (4 кости к6). Используйте для телепатии (1 миля) или Пси-подкреплённых навыков."},
    {"name": "Психические лезвия", "level": 3, "description": "Бонусным действием создайте психический клинок (1к6 психического). Дальность 60 футов. Исчезает после атаки."},
    {"name": "Душа-клинок", "level": 9, "description": "Бонусным действием совершите вторую атаку клинком. Если обе промахиваются — не тратьте кость."},
    {"name": "Психическая вуаль", "level": 13, "description": "Действием станьте невидимым с одним согласным существом на 1 час. Заканчивается при атаке."},
    {"name": "Разрыв разума", "level": 17, "description": "Три кости Псионической энергии: заставьте существо в 30 футах пройти Мудрость или оглушиться."}
  ]}
]'::jsonb WHERE name_en = 'Rogue';

-- Update Sorcerer with subclasses (Sorcerous Origins)
UPDATE public.classes SET subclasses = '[
  {"name": "Драконья кровь", "name_en": "Draconic Bloodline", "level": 1, "description": "Ваша магия происходит от драконьего предка.", "features": [
    {"name": "Предок-дракон", "level": 1, "description": "Выберите тип дракона (чёрный/кислота, синий/молния, зелёный/яд, красный/огонь, белый/холод и т.д.). Вы говорите на Драконьем языке. Удваивается бонус мастерства при взаимодействии с драконами."},
