    {"name": "Драконье присутствие", "level": 18, "description": "Действием: существа в 60 футах должны пройти Мудрость или быть очарованы/испуганы на 1 минуту. 5 очков чародейства."}
  ]},
  {"name": "Дикая магия", "name_en": "Wild Magic", "level": 1, "description": "Ваша магия происходит из хаоса и непредсказуемости.", "features": [
    {"name": "Всплеск дикой магии", "level": 1, "description": "После заклинания 1+ круга Мастер может попросить бросить к20. При 1 — бросьте по таблице Дикой магии."},
    {"name": "Приливы хаоса", "level": 1, "description": "Преимущество на бросок атаки, проверку или спасбросок. Затем Мастер может вызвать всплеск после заклинания."},
    {"name": "Изгиб удачи", "level": 6, "description": "Реакцией добавьте или вычтите 1к4 к броску атаки, проверки или спасброска существа в 60 футах. 2 очка чародейства."},
    {"name": "Контролируемый хаос", "level": 14, "description": "При броске по таблице Дикой магии бросьте дважды и выберите результат."},
    {"name": "Бомбардировка заклинаниями", "level": 18, "description": "При максимуме на кости урона заклинания бросьте эту кость ещё раз и добавьте."}
  ]},
  {"name": "Божественная душа", "name_en": "Divine Soul", "level": 1, "description": "Божественная сила течёт в вас, давая доступ к заклинаниям жреца.", "features": [
    {"name": "Божественная магия", "level": 1, "description": "Вы можете выбирать заклинания из списка чародея и жреца. Выберите сродство: Добро (Благословение), Зло (Погибель), Закон (Благословение), Хаос (Погибель), Нейтральность (Защита от добра и зла)."},
    {"name": "Избранный богами", "level": 1, "description": "При провале спасброска или промахе добавьте 2к4 к броску. Раз между отдыхами."},
    {"name": "Наделённое исцеление", "level": 6, "description": "При восстановлении хитов заклинанием потратьте 1 очко чародейства: перебросьте кости исцеления."},
    {"name": "Потусторонние крылья", "level": 14, "description": "Бонусным действием создайте призрачные крылья. Скорость полёта 30 футов."},
    {"name": "Неземной облик", "level": 18, "description": "Потратьте 1 очко чародейства для 4 часов трансформации: слепое зрение 60 футов, скорость полёта 30, сопротивление дробящему/колющему/рубящему."}
  ]},
  {"name": "Заводное сердце", "name_en": "Clockwork Soul", "level": 1, "description": "Ваша магия связана с силами порядка и механизмов.", "features": [
    {"name": "Заклинания заводного мага", "level": 1, "description": "Дополнительные заклинания: Тревога, Защита от добра и зла (1), Помощь, Малое восстановление (3), Защита от энергии, Рассеивание магии (5), Свобода передвижения, Призыв конструкта (7), Высшее восстановление, Стена силы (9)."},
    {"name": "Восстановление баланса", "level": 1, "description": "Реакцией при атаке с преимуществом/помехой в 60 футах отмените преимущество/помеху. Мастерство раз между продолжительными отдыхами."},
    {"name": "Оплот закона", "level": 6, "description": "Действием выберите существо в 30 футах. Потратьте 1-5 очков чародейства: оно получает защитную ауру (уменьшение урона на к8 × потраченные очки) на число атак = потраченные очки."},
    {"name": "Такт хаоса", "level": 14, "description": "Раз между продолжительными отдыхами получите преимущество на бросок атаки, проверку или спасбросок. Или дайте помеху существу в 60 футах."},
    {"name": "Заводной кавалькад", "level": 18, "description": "Действием на 1 минуту: восстановите 5 HP в начале хода, КД+2, преимущество на атаку/спасброски, враги в 30 футах с помехой на атаку по вам. 7 очков чародейства."}
  ]}
]'::jsonb WHERE name_en = 'Sorcerer';

